module top_module(input wire clk, vgae2, 
                input wire [7:0] e,
                output wire [3:0] num);reg [3:0] unused_aux;

  always @(e, vgae2) 
  begin
    if (vgae2) 
    begin
      case (e[3:0])              
        4'b0000: unused_aux = 0;
        4'b0001: unused_aux = 1;
        4'b0010: unused_aux = 2;
        4'b0011: unused_aux = 3;
        4'b0100: unused_aux = 4;
        4'b0101: unused_aux = 5;
        4'b0110: unused_aux = 6;
        4'b0111: unused_aux = 7;
        4'b1000: unused_aux = 8;
        4'b1001: unused_aux = 9;
        default: unused_aux = 15;  
      endcase
    end      
  end

  assign num = unused_aux;

endmodule
